@typeparam TItem

@if (Items is not null && Items.Any())
{
    <table class="@CssClass">
        <thead>
            <tr>
                @HeaderTemplate
            </tr>
        </thead>
        <tbody>
            @foreach (var item in Items)
            {
                <tr @onclick="() => OnRowClick.InvokeAsync(item)">
                    @RowTemplate(item)
                </tr>
            }
        </tbody>
    </table>
}
else
{
    @if (EmptyTemplate is not null)
    {
        @EmptyTemplate
    }
    else
    {
        <p>No items to display.</p>
    }
}

@code {
    [Parameter, EditorRequired]
    public IEnumerable<TItem> Items { get; set; } = default!;

    [Parameter, EditorRequired]
    public RenderFragment HeaderTemplate { get; set; } = default!;

    [Parameter, EditorRequired]
    public RenderFragment<TItem> RowTemplate { get; set; } = default!;

    [Parameter]
    public RenderFragment? EmptyTemplate { get; set; }

    [Parameter]
    public EventCallback<TItem> OnRowClick { get; set; }

    [Parameter]
    public string? CssClass { get; set; }
}

